var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"방금...... 뭐라고 했지?","JPN":"今……なんて言った……？","ENG":"What... did you just say?","TWN":"你剛才……說什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"귀가 먹었나? 왜 자꾸 두 번이나 말하게 하는 거야.","JPN":"耳が遠くなったか？　二度も言わせるな。","ENG":"Are you going deaf? Don't make me repeat myself.","TWN":"你聾了嗎？還要我說多少次。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"췌장암이야. 6개월 정도 남았을 걸.","JPN":"すい臓がんだよ。余命6ヵ月ぐらいかな。","ENG":"Pancreatic cancer. I've got about six months left.","TWN":"是胰腺癌，還能活6個月左右。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......진료소로 가자. 솜씨 좋은 야매를 한 명 알아.","JPN":"……病院に行こう。腕のいい闇医者を知っている。","ENG":"Let me get you to a clinic. I know a pretty capable quack.","TWN":"……去診所吧，我認識一個不錯的無證醫生。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"우리 대장, 개그 솜씨가 꽤 늘었네.","JPN":"いやーうちの隊長、冗談も言えるようになってきたな。","ENG":"My, you've grown a sense of humor, Captain.","TWN":"隊長，你還真會開玩笑。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"췌장암이 무슨 골절 같은 건 줄 알아? 야매가 대충 기워 주면 고쳐지게?","JPN":"すい臓がんを骨折か何かと勘違いしてるんじゃないか？　闇医者に診てもらえれば治るって？","ENG":"This is cancer. You can't just have a quack stitch you up like a bullet wound.","TWN":"你以為胰腺癌是骨折嗎？無證醫生怎麼可能會治好？"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그러니까...... 이게 내 은퇴식이야.","JPN":"だから……これは俺の引退式だ。","ENG":"So... this will be my retirement ceremony.","TWN":"所以……這次是我的退役儀式。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"자살이라도 할 생각이냐! 일부러 배신한 척 하겠다니...... 그딴 생각은 집어치워.","JPN":"自殺でもするつもりか？　裏切ったフリをするなんて……やめておけ。","ENG":"You're going to get yourself killed! This fake betrayal of yours... don't even think about it.","TWN":"你想自殺嗎！還假裝背叛我們……你快停手。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......하지만 대장도 알잖아.","JPN":"隊長もわかってるだろ。","ENG":"But you know it deep down, don't you?","TWN":"……但是隊長你也知道的。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"이런 총알 같은 걸로는 성냥팔이 놈에게 흠집 하나 못 내고 뒈진다는 거.","JPN":"こんな武器じゃ、マッチ売りの奴にかすり傷すら残せず全滅だ。","ENG":"Bullets like these won't even leave a scratch on the Matchmaker.","TWN":"子彈對賣火柴的構不成任何傷害。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭐, 폭탄이 통할지도 잘 모르겠지만 그래도 가능성은 더 높겠지.","JPN":"まあ、爆弾が効くかどうかもわからないが、他の手段より可能性は高いだろう。","ENG":"Then again, I guess there's no guarantee bombs will work either. Still, it's a better shot.","TWN":"雖然不知道炸彈能不能起作用，但至少應該比子彈有用吧。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"정말......","JPN":"本当に……","ENG":"Do you...","TWN":"真的……"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"정말, 그런 방법밖에 없다고 생각하나?","JPN":"本当にそれしか方法がないと思ってるのか？","ENG":"Do you really think that's the only way?","TWN":"真的沒有別的辦法了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"명색이 민병대인데, 잎새 떨어지는 거나 지켜보면서 천천히 죽고 싶진 않아.","JPN":"一応民兵隊に所属してるんだ。病室で木の葉が落ちるのを眺めながら穏やかに死にたくなんてないさ。","ENG":"We're the Militia after all. I don't plan on dying boringly of old age.","TWN":"我好歹是民兵隊，總不能在病床上等死。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그래서야 먼저 간 동료들 볼 때 체면이 안 서지, 안 그래?","JPN":"そんなんじゃ先に逝った仲間に会う時、メンツが立たないだろ。そう思わないか？","ENG":"What am I going to say to our fallen brothers and sisters if I die such a lame death?","TWN":"不然我就沒臉去見先走一步的同伴們了，對吧？"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"곧 죽을 놈 걱정해 줄 여유 있으면 신참이나 잘 돌봐 줘.","JPN":"もうすぐ死ぬ奴を心配する余裕があるなら、新入りの世話に力を入れてやれ。","ENG":"You might as well as take better care of the rookie if you've got the time to worry about me.","TWN":"有閒功夫關心我這個瀕死之人，不如多照顧照顧新人吧。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그 녀석은 적어도 아직은...... 우리 같은 쓰레기가 아니라 진짜 민병대니까.","JPN":"あいつだけはまだ……少なくとも、俺らみたいなクズじゃなくて、本物の民兵隊だ。","ENG":"At the very least... she's still a real Militiaman, not a scumbag like us.","TWN":"至少那傢伙還不是像我們這樣的垃圾……而是真正的民兵隊。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......알겠다.","JPN":"……わかった。","ENG":"...Okay.","TWN":"……知道了。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그간 도와 줘서 고마웠다. 최지훈.","JPN":"今まで力になってくれて感謝する、ゴトウ・トシノリ。","ENG":"I appreciate all you've done to help, Jihoon.","TWN":"謝謝你一直以來的照顧，崔智勳。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"닭살 돋는 소리 하지 마, 대장.","JPN":"やめてくれよ、鳥肌が立つだろ。","ENG":"Ugh, don't get all touchy-feely with me now, Captain.","TWN":"別說這種肉麻的話，隊長。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아, 그리고 내 동생 말인데......","JPN":"ああ、俺の妹のことなんだが……","ENG":"And as for my sister...","TWN":"對了，我的弟弟……"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"죽기 전에...... 경찰 아저씨들 원망은 하지 않으니까 걱정 말라고 하더라고.","JPN":"死ぬ前に……警察のおじさんたちのことは恨んでないから心配しないで、と言っていた。","ENG":"She said she didn't blame the cops before she died. She didn't want you to feel guilty about her death.","TWN":"他臨死前說……自己不會埋怨員警叔叔們，叫他們不要愧疚。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"최지훈......","JPN":"ゴトウ……","ENG":"Jihoon...","TWN":"崔智勳……"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭐, 그렇다고.","JPN":"まあ、ってことで。","ENG":"Just saying, you know.","TWN":"就這樣了。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뒷 일이나 잘 부탁해.","JPN":"あとはよろしくな。","ENG":"Don't mess up the rest once I'm gone, will you?","TWN":"後事就拜託了。"},"stage":{"bg":"BACKSTREET2","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};